#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-18

# ============================================================================
# Eval Coverage Ratchet (#2192)
# ============================================================================
# Fails CI when any shipped component (skill or agent) has no eval spec. This is
# the hard gate; scripts/eval/static-analysis.sh only reports coverage advisory.
#
# Source of truth: scripts/eval/eval-coverage.sh --check, which enumerates
#   src/skills/*/SKILL.md   vs  tests/evals/skills/*.eval.yaml
#   src/agents/*.md (w/ frontmatter)  vs  tests/evals/agents/*.eval.yaml
# and exits non-zero listing every uncovered component. Add a spec (or run
# `bash scripts/eval/eval-coverage.sh --fill`) to clear the gate.
# ============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"
WALKER="$PROJECT_ROOT/scripts/eval/eval-coverage.sh"

if [[ -t 1 ]]; then
  RED='\033[0;31m'; GREEN='\033[0;32m'; NC='\033[0m'
else
  RED=''; GREEN=''; NC=''
fi

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

echo "Eval Coverage Ratchet (#2192)"

if [[ ! -x "$WALKER" ]] && [[ ! -f "$WALKER" ]]; then
  log_fail "walker not found at $WALKER"
  exit 1
fi

# --check regenerates coverage.json and exits 1 if any component is uncovered.
CHECK_RC=0
CHECK_OUT="$(bash "$WALKER" --check 2>&1)" || CHECK_RC=$?

if [[ $CHECK_RC -eq 0 ]]; then
  log_pass "every skill and agent has an eval spec"
else
  log_fail "uncovered component(s) without an eval spec:"
  echo "$CHECK_OUT" | sed 's/^/      /'
fi

# Cross-check the emitted coverage.json agrees (uncovered_total == 0).
COV_JSON="$PROJECT_ROOT/tests/evals/results/coverage.json"
if [[ -f "$COV_JSON" ]]; then
  COV_N="$(grep -o '"uncovered_total"[: ]*[0-9]*' "$COV_JSON" | grep -o '[0-9]*' | head -1)"
  if [[ "${COV_N:-1}" -eq 0 ]]; then
    log_pass "coverage.json reports uncovered_total=0"
  else
    log_fail "coverage.json reports uncovered_total=${COV_N}"
  fi
else
  log_fail "coverage.json not written at $COV_JSON"
fi

echo ""
echo -e "  Passed: ${GREEN}${PASS}${NC}  Failed: ${RED}${FAIL}${NC}"
[[ $FAIL -eq 0 ]] || exit 1
exit 0
